// Monta o body do PUT com apenas os campos preenchidos
const input = $input.first().json;
const lead_id = input.lead_id;
const body = {};

if (input.nome) body.nome = input.nome;
if (input.email) body.email = input.email;
if (input.destinos) body.destinos = input.destinos;
if (input.data_chegada) body.data_chegada = input.data_chegada;
if (input.data_partida) body.data_partida = input.data_partida;
if (input.num_viajantes) {
  body.campos_personalizados = { ...(body.campos_personalizados || {}), num_viajantes: String(input.num_viajantes) };
}

return [{ json: { lead_id, body } }];
